import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

// Assuming the function is exported from a module named 'truncate'
import { truncateContent } from './truncate';

describe('truncateContent', () => {
  it('should handle happy path', () => {
    const input = 'This is a sample string that is definitely longer than eighty characters so it should be truncated properly';
    const result = truncateContent(input, 80);
    // Since the input length > 80, expect it to be truncated and ending with '...'
    expect(result.length).toBeLessThanOrEqual(80);
    expect(result).toEndWith('...');
  });

  it('should handle edge case when content length equals maxLength', () => {
    const exactLengthString = 'a'.repeat(80);
    const result = truncateContent(exactLengthString, 80);
    // Should return the same string without truncation
    expect(result).toBe(exactLengthString);
  });

  it('should handle null/empty inputs', () => {
    // Null input
    expect(truncateContent(null as unknown as string, 80)).toBe('');
    // Undefined input
    expect(truncateContent(undefined as unknown as string, 80)).toBe('');
    // Empty string
    expect(truncateContent('', 80)).toBe('');
    // Zero maxLength
    expect(truncateContent('Hello', 0)).toBe('');
  });
});

